import httpx
import json
from typing import Callable

# Primary: Tavily search
def tavily_search(query: str, max_results: int = 5) -> list[dict]:
    from tavily import TavilyClient
    client = TavilyClient(api_key=TAVILY_API_KEY)
    response = client.search(query=query, max_results=max_results)
    return [{"title": r["title"], "url": r["url"], "content": r["content"]}
            for r in response["results"]]

# Fallback: DuckDuckGo (no API key required)
def duckduckgo_search(query: str, max_results: int = 5) -> list[dict]:
    from duckduckgo_search import DDGS
    with DDGS() as ddgs:
        results = list(ddgs.text(query, max_results=max_results))
    return [{"title": r["title"], "url": r["href"], "content": r["body"]}
            for r in results]

def web_search_with_fallback(query: str, max_results: int = 5) -> list[dict]:
    """Try Tavily; fall back to DuckDuckGo on any failure."""
    try:
        return tavily_search(query, max_results)
    except Exception as primary_err:
        try:
            results = duckduckgo_search(query, max_results)
            # Tag fallback results so the LLM knows the source
            for r in results:
                r["_fallback"] = True
            return results
        except Exception as fallback_err:
            raise RuntimeError(
                f"Both search providers failed. "
                f"Primary: {primary_err}. Fallback: {fallback_err}."
            ) from fallback_err

# Tool wrapper always returns a string
def tool_web_search(query: str, max_results: int = 5) -> str:
    try:
        results = web_search_with_fallback(query, max_results)
        source = "DuckDuckGo (fallback)" if results and results[0].get("_fallback") else "Tavily"
        lines = [f"Results via {source}:\n"]
        for i, r in enumerate(results, 1):
            lines.append(f"[{i}] {r['title']}\nURL: {r['url']}\n{r['content']}\n")
        return "\n".join(lines)
    except RuntimeError as e:
        return json.dumps({"error": str(e)})

import json
import time
from functools import wraps

class TTLCache:
    """Simple in-memory TTL cache (use Redis in production)."""
    def __init__(self):
        self._store: dict[str, tuple[float, any]] = {}

    def get(self, key: str):
        entry = self._store.get(key)
        if entry is None:
            return None
        expires_at, value = entry
        return value if time.time() < expires_at else None

    def set(self, key: str, value, ttl: int = 300):
        self._store[key] = (time.time() + ttl, value)

    def get_stale(self, key: str):
        """Return the value even if expired (for fallback use)."""
        entry = self._store.get(key)
        return entry[1] if entry else None

cache = TTLCache()

def get_product_info(product_id: str) -> str:
    """Fetch product details with cache fallback on API failure."""
    cache_key = f"product:{product_id}"

    # Try live API
    try:
        import httpx
        resp = httpx.get(
            f"https://api.example.com/products/{product_id}",
            timeout=3,
        )
        resp.raise_for_status()
        data = resp.json()
        cache.set(cache_key, data, ttl=300)  # cache for 5 minutes
        return json.dumps(data)

    except Exception as e:
        # Try stale cache
        stale = cache.get_stale(cache_key)
        if stale:
            stale["_warning"] = "Live data unavailable; this result may be up to 5 minutes old."
            return json.dumps(stale)

        return json.dumps({
            "error": f"Product API unavailable and no cached data for '{product_id}'.",
            "detail": str(e),
        })

