from dataclasses import dataclass
from typing import Callable, Optional
import json

@dataclass
class FallbackChain:
    """Try each provider in order; return the first success."""
    providers: list[tuple[str, Callable]]  # (label, fn)

    def call(self, **kwargs) -> tuple[str, str]:
        """Returns (label_used, result_json)."""
        errors = []
        for label, fn in self.providers:
            try:
                result = fn(**kwargs)
                return label, json.dumps(result, default=str)
            except Exception as e:
                errors.append(f"{label}: {e}")

        error_summary = "; ".join(errors)
        return "none", json.dumps({"error": f"All providers failed: {error_summary}"})

document_search_chain = FallbackChain(providers=[
    ("elastic_search",  lambda **kw: elastic_search(**kw)),   # primary: Elasticsearch
    ("vector_search",   lambda **kw: chroma_search(**kw)),    # fallback 1: Chroma vector DB
    ("keyword_fallback",lambda **kw: bm25_search(**kw)),      # fallback 2: BM25 in-memory
])

def tool_search_documents(query: str, top_k: int = 5) -> str:
    label, result = document_search_chain.call(query=query, top_k=top_k)
    if label != "elastic_search":
        # Inform the LLM which fallback was used
        data = json.loads(result)
        if "error" not in data:
            return json.dumps({
                "results": data,
                "_source": label,
                "_note": f"Returned via fallback provider ({label}); results may differ from primary.",
            })
    return result

import time
from enum import Enum

class State(Enum):
    CLOSED = "closed"
    OPEN = "open"
    HALF_OPEN = "half_open"

class CircuitBreaker:
    def __init__(
        self,
        failure_threshold: int = 3,
        recovery_timeout: float = 60.0,
    ):
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self.state = State.CLOSED
        self.failure_count = 0
        self.last_failure_time: float = 0.0

    def call(self, primary_fn, fallback_fn, **kwargs):
        if self.state == State.OPEN:
            if time.time() - self.last_failure_time > self.recovery_timeout:
                self.state = State.HALF_OPEN
            else:
                return fallback_fn(**kwargs)   # skip primary entirely

        try:
            result = primary_fn(**kwargs)
            self._on_success()
            return result
        except Exception as exc:
            self._on_failure()
            return fallback_fn(**kwargs)

    def _on_success(self):
        self.failure_count = 0
        self.state = State.CLOSED

    def _on_failure(self):
        self.failure_count += 1
        self.last_failure_time = time.time()
        if self.failure_count >= self.failure_threshold:
            self.state = State.OPEN

# Usage
breaker = CircuitBreaker(failure_threshold=3, recovery_timeout=60.0)

