import logging
import json
from datetime import datetime, timezone

logger = logging.getLogger("tool.fallback")

class ObservableFallbackChain:
    def __init__(self, name: str, providers: list[tuple[str, callable]]):
        self.name = name
        self.providers = providers
        self._fallback_counts: dict[str, int] = {}

    def call(self, **kwargs) -> tuple[str, str]:
        errors = []
        for label, fn in self.providers:
            try:
                result = fn(**kwargs)
                if label != self.providers[0][0]:   # not the primary
                    count = self._fallback_counts.get(label, 0) + 1
                    self._fallback_counts[label] = count
                    logger.warning(
                        "FALLBACK used for tool=%s provider=%s count=%d args=%s",
                        self.name, label, count, json.dumps(kwargs, default=str)[:200],
                    )
                return label, json.dumps(result, default=str)
            except Exception as e:
                errors.append(f"{label}: {e}")
                logger.error(
                    "Tool provider failed: tool=%s provider=%s error=%s",
                    self.name, label, e,
                )

        # All failed
        logger.critical(
            "ALL providers failed for tool=%s errors=%s",
            self.name, errors,
        )
        return "none", json.dumps({"error": f"All providers failed: {'; '.join(errors)}"})

    def get_stats(self) -> dict:
        return {"tool": self.name, "fallback_counts": self._fallback_counts}
